import React, { useEffect, useState, useCallback } from "react";
import {
  Search, RefreshCw, FileText, Edit, Eye, Share2, Save
} from "lucide-react";
import { getArticles, updateArticleStatus, updateArticleNote } from "../api";

const token = process.env.REACT_APP_JWT_TOKEN;

const Articles = ({
  filters, setFilters, searchQuery, setSearchQuery,
  categories, getStatusColor, getStatusIcon
}) => {
  const [articles, setArticles] = useState([]);
  const [loading, setLoading] = useState(false);
  const [editingNote, setEditingNote] = useState(null);
  const [notes, setNotes] = useState({}); // { [id]: note string }

  // --- Fetch Articles from API ---
  const fetchArticles = useCallback(async () => {
    setLoading(true);
    try {
      const params = {};
      if (filters.category && filters.category !== "all")
        params.category = filters.category;
      if (filters.status && filters.status !== "all")
        params.status = filters.status;
      if (searchQuery)
        params.search = searchQuery;
      // Add source, relevance etc if needed
      const data = await getArticles(token, params);
      setArticles(data || []);
      // Optionally update notes state if your backend returns notes
      let notesObj = {};
      (data || []).forEach(article => {
        if (article.note) notesObj[article.id] = article.note;
      });
      setNotes(notesObj);
    } catch (err) {
      console.error("Error fetching articles", err);
    }
    setLoading(false);
  }, [filters, searchQuery]);

  useEffect(() => {
    fetchArticles();
  }, [fetchArticles]);

  // --- Handlers for status and note ---
  const handleStatusChange = async (articleId, newStatus) => {
    try {
      await updateArticleStatus(articleId, newStatus, token);
      fetchArticles();
    } catch (err) {
      alert("Failed to update status.");
    }
  };

  const handleNoteSave = async (articleId, note) => {
    try {
      await updateArticleNote(articleId, note, token);
      setNotes((prev) => ({ ...prev, [articleId]: note }));
      setEditingNote(null);
    } catch (err) {
      alert("Failed to save note.");
    }
  };

  // --- UI ---
  return (
    <div className="p-6 space-y-4">
      <div className="bg-white rounded-lg shadow p-4">
        <div className="flex flex-wrap gap-4 items-center">
          <div className="flex-1 min-w-[200px]">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-5 h-5" />
              <input
                type="text"
                placeholder="Search articles..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-10 pr-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
          </div>
          <select
            value={filters.category}
            onChange={(e) => setFilters({ ...filters, category: e.target.value })}
            className="px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value="all">All Categories</option>
            {categories.map(cat => (
              <option key={cat.id} value={cat.name}>{cat.name}</option>
            ))}
          </select>
          <select
            value={filters.status}
            onChange={(e) => setFilters({ ...filters, status: e.target.value })}
            className="px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value="all">All Status</option>
            <option value="new">New</option>
            <option value="reviewed">Reviewed</option>
            <option value="shortlisted">Shortlisted</option>
            <option value="final">Final</option>
          </select>
          <button
            onClick={fetchArticles}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 flex items-center gap-2"
            disabled={loading}
          >
            <RefreshCw className={`w-4 h-4 ${loading ? "animate-spin" : ""}`} />
            Refresh
          </button>
        </div>
      </div>
      <div className="space-y-4">
        {loading ? (
          <div className="text-center py-8 text-gray-500">Loading...</div>
        ) : articles.length === 0 ? (
          <div className="text-center py-8 text-gray-400">No articles found.</div>
        ) : (
          articles.map(article => (
            <div key={article.id} className="bg-white rounded-lg shadow hover:shadow-lg transition-shadow">
              <div className="p-6">
                <div className="flex items-start justify-between mb-4">
                  <div className="flex-1">
                    <h3 className="text-lg font-semibold text-gray-900 mb-2">{article.title}</h3>
                    <div className="flex items-center gap-4 text-sm text-gray-500 mb-3">
                      <span>{article.source || (article.meta_data && article.meta_data.link)}</span>
                      <span>•</span>
                      <span>{article.date ? new Date(article.date).toLocaleDateString() : ""}</span>
                      <span>•</span>
                      <span className="text-blue-600 font-medium">Score: {article.relevanceScore ?? "—"}%</span>
                    </div>
                    <p className="text-gray-600 mb-3">{article.summary}</p>
                    {article.tags && (
                      <div className="flex flex-wrap gap-2 mb-4">
                        {article.tags.map(tag => (
                          <span key={tag} className="px-2 py-1 bg-gray-100 text-gray-600 rounded text-sm">
                            {tag}
                          </span>
                        ))}
                      </div>
                    )}
                    {article.metrics && (
                      <div className="flex items-center gap-4 text-sm text-gray-500">
                        <span className="flex items-center gap-1">
                          <Eye className="w-4 h-4" /> {article.metrics.views}
                        </span>
                        <span className="flex items-center gap-1">
                          <Share2 className="w-4 h-4" /> {article.metrics.shares}
                        </span>
                        <span className="flex items-center gap-1">
                          <Save className="w-4 h-4" /> {article.metrics.saves}
                        </span>
                      </div>
                    )}
                  </div>
                </div>
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <span className={`px-3 py-1 rounded-full text-sm font-medium flex items-center gap-1 ${getStatusColor(article.status)}`}>
                      {getStatusIcon(article.status)}
                      {article.status}
                    </span>
                    <select
                      value={article.status}
                      onChange={(e) => handleStatusChange(article.id, e.target.value)}
                      className="px-3 py-1 border rounded text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                    >
                      <option value="new">New</option>
                      <option value="reviewed">Reviewed</option>
                      <option value="shortlisted">Shortlisted</option>
                      <option value="final">Final</option>
                    </select>
                  </div>
                  <div className="flex items-center gap-2">
                    <button className="px-3 py-1 text-blue-600 hover:bg-blue-50 rounded flex items-center gap-1">
                      <FileText className="w-4 h-4" />
                      View Full
                    </button>
                    <button
                      onClick={() => setEditingNote(article.id)}
                      className="px-3 py-1 text-gray-600 hover:bg-gray-50 rounded flex items-center gap-1"
                    >
                      <Edit className="w-4 h-4" />
                      {notes[article.id] ? "Edit Note" : "Add Note"}
                    </button>
                  </div>
                </div>
                {editingNote === article.id && (
                  <div className="mt-4 p-3 bg-gray-50 rounded">
                    <textarea
                      className="w-full p-2 border rounded text-sm"
                      placeholder="Add a note..."
                      rows="3"
                      defaultValue={notes[article.id] || ""}
                      onBlur={(e) => {
                        handleNoteSave(article.id, e.target.value);
                      }}
                    />
                  </div>
                )}
                {notes[article.id] && (
                  <div className="mt-4 p-3 bg-blue-50 rounded">
                    <p className="text-sm text-gray-700">
                      <span className="font-medium">Note:</span> {notes[article.id]}
                    </p>
                  </div>
                )}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default Articles;
